import hmac
import hashlib
import logging
from flask import Blueprint, request, jsonify
from config import GITHUB_WEBHOOK_SECRET
from ci.runner import trigger_ci

log = logging.getLogger(__name__)
github_bp = Blueprint('github_webhooks', __name__)

CI_TRIGGER_ACTIONS = {'opened', 'synchronize', 'reopened'}


def verify_signature(payload: bytes, signature: str) -> bool:
    expected = 'sha256=' + hmac.new(
        GITHUB_WEBHOOK_SECRET.encode(),
        msg=payload,
        digestmod=hashlib.sha256
    ).hexdigest()
    return hmac.compare_digest(expected, signature)


@github_bp.route('/webhooks/github', methods=['POST'])
def handle_webhook():
    signature = request.headers.get('X-Hub-Signature-256', '')
    if not verify_signature(request.get_data(), signature):
        return jsonify({'error': 'Invalid signature'}), 401

    event = request.headers.get('X-GitHub-Event')
    if event != 'pull_request':
        return jsonify({'status': 'ignored'})

    payload = request.get_json()
    action = payload.get('action')
    if action not in CI_TRIGGER_ACTIONS:
        return jsonify({'status': 'ignored'})

    pr = payload['pull_request']
    log.info('CI triggered for PR #%s (%s)', payload['number'], action)
    trigger_ci(
        repo=payload['repository']['full_name'],
        pr_number=payload['number'],
        sha=pr['head']['sha'],
        branch=pr['head']['ref']
    )
    return jsonify({'status': 'triggered'})
